Review the following code and identify all bugs, security vulnerabilities, and performance issues. Provide fixed code.

```python
import sqlite3
import pickle
from flask import Flask, request, jsonify

app = Flask(__name__)
db = sqlite3.connect('app.db')

@app.route('/user/<name>')
def get_user(name):
    cursor = db.execute(f"SELECT * FROM users WHERE name='{name}'")
    user = cursor.fetchone()
    return jsonify({'user': user})

@app.route('/upload', methods=['POST'])
def upload():
    data = pickle.loads(request.data)
    db.execute(f"INSERT INTO uploads VALUES ('{data['name']}', '{data['content']}')")
    db.commit()
    return 'OK'

@app.route('/search')
def search():
    query = request.args.get('q')
    results = db.execute(f"SELECT * FROM items WHERE description LIKE '%{query}%'")
    return jsonify([dict(r) for r in results])
```

